CREATE TABLE roles(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(80) UNIQUE,created_at DATETIME);CREATE TABLE permissions(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) UNIQUE);CREATE TABLE users(id INT AUTO_INCREMENT PRIMARY KEY,role_id INT DEFAULT 1,name VARCHAR(160),email VARCHAR(190) UNIQUE,password_hash VARCHAR(255),status VARCHAR(30) DEFAULT 'active',verification_token VARCHAR(80),reset_token VARCHAR(120),reset_expires DATETIME,created_at DATETIME,INDEX(email));CREATE TABLE sessions(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,token_hash VARCHAR(255),expires_at DATETIME,created_at DATETIME);CREATE TABLE wallets(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT UNIQUE,balance DECIMAL(12,2) DEFAULT 0,promo_balance DECIMAL(12,2) DEFAULT 0,currency CHAR(3) DEFAULT 'USD',created_at DATETIME);CREATE TABLE wallet_requests(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,amount DECIMAL(12,2),method VARCHAR(50),transaction_id VARCHAR(190),proof_path VARCHAR(255),status VARCHAR(30),admin_note TEXT,reviewed_by INT,reviewed_at DATETIME,created_at DATETIME);CREATE TABLE transactions(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,type VARCHAR(40),amount DECIMAL(12,2),status VARCHAR(40),reference VARCHAR(190),created_at DATETIME);CREATE TABLE gift_card_categories(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120),slug VARCHAR(150) UNIQUE);CREATE TABLE gift_card_brands(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(160),slug VARCHAR(180) UNIQUE,logo_url VARCHAR(255));CREATE TABLE gift_card_countries(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120),iso_code CHAR(2) UNIQUE,currency CHAR(3));CREATE TABLE gift_cards(id INT AUTO_INCREMENT PRIMARY KEY,reloadly_product_id VARCHAR(80),brand_id INT,category_id INT,country_id INT,name VARCHAR(190),description TEXT,country_code CHAR(2),currency CHAR(3),price DECIMAL(12,2),original_price DECIMAL(12,2),markup_percent DECIMAL(5,2) DEFAULT 8,discount_percent DECIMAL(5,2) DEFAULT 0,denominations JSON,enabled TINYINT DEFAULT 1,featured TINYINT DEFAULT 0,stock INT DEFAULT 999,created_at DATETIME);CREATE TABLE orders(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,total DECIMAL(12,2),currency CHAR(3),status VARCHAR(40),invoice_number VARCHAR(80),created_at DATETIME);CREATE TABLE order_items(id INT AUTO_INCREMENT PRIMARY KEY,order_id INT,gift_card_id INT,quantity INT,unit_price DECIMAL(12,2),total DECIMAL(12,2));CREATE TABLE gift_codes(id INT AUTO_INCREMENT PRIMARY KEY,order_item_id INT,code TEXT,pin VARCHAR(190),barcode TEXT,redeem_url TEXT,created_at DATETIME);CREATE TABLE notifications(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,title VARCHAR(190),body TEXT,read_at DATETIME,created_at DATETIME);CREATE TABLE emails(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,template VARCHAR(80),subject VARCHAR(190),status VARCHAR(40),created_at DATETIME);CREATE TABLE support_tickets(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,subject VARCHAR(190),status VARCHAR(40),created_at DATETIME);CREATE TABLE messages(id INT AUTO_INCREMENT PRIMARY KEY,ticket_id INT,user_id INT,body TEXT,created_at DATETIME);CREATE TABLE favorites(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,gift_card_id INT,UNIQUE(user_id,gift_card_id));CREATE TABLE wishlists(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,gift_card_id INT,created_at DATETIME);CREATE TABLE reviews(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,gift_card_id INT,body TEXT,created_at DATETIME);CREATE TABLE ratings(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,gift_card_id INT,rating INT,UNIQUE(user_id,gift_card_id));CREATE TABLE referrals(id INT AUTO_INCREMENT PRIMARY KEY,referrer_id INT,referred_id INT,code VARCHAR(80),created_at DATETIME);CREATE TABLE affiliate_clicks(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,ip VARCHAR(64),created_at DATETIME);CREATE TABLE affiliate_payouts(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT,amount DECIMAL(12,2),status VARCHAR(40),created_at DATETIME);CREATE TABLE coupons(id INT AUTO_INCREMENT PRIMARY KEY,code VARCHAR(80) UNIQUE,type VARCHAR(40),value DECIMAL(12,2),starts_at DATETIME,ends_at DATETIME,active TINYINT DEFAULT 1);CREATE TABLE coupon_usage(id INT AUTO_INCREMENT PRIMARY KEY,coupon_id INT,user_id INT,order_id INT,created_at DATETIME);CREATE TABLE settings(id INT AUTO_INCREMENT PRIMARY KEY,setting_key VARCHAR(120) UNIQUE,setting_value TEXT);CREATE TABLE logs(id INT AUTO_INCREMENT PRIMARY KEY,level VARCHAR(30),message TEXT,created_at DATETIME);CREATE TABLE admin_logs(id INT AUTO_INCREMENT PRIMARY KEY,admin_id INT,action VARCHAR(190),payload JSON,created_at DATETIME);CREATE TABLE api_logs(id INT AUTO_INCREMENT PRIMARY KEY,path VARCHAR(190),status VARCHAR(50),message TEXT,created_at DATETIME);CREATE TABLE reloadly_tokens(id INT AUTO_INCREMENT PRIMARY KEY,access_token TEXT,expires_at DATETIME,created_at DATETIME);CREATE TABLE reloadly_cache(id INT AUTO_INCREMENT PRIMARY KEY,cache_key VARCHAR(190) UNIQUE,payload JSON,expires_at DATETIME);CREATE TABLE failed_jobs(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(190),payload JSON,error TEXT,created_at DATETIME);CREATE TABLE cron_jobs(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(190),last_run_at DATETIME,status VARCHAR(40));INSERT INTO roles(name,created_at) VALUES('customer',NOW()),('admin',NOW());INSERT INTO gift_card_categories(name,slug) VALUES('Gaming','gaming'),('Entertainment','entertainment'),('Streaming','streaming'),('Shopping','shopping'),('Mobile','mobile'),('Food','food'),('Travel','travel'),('Crypto','crypto'),('Utilities','utilities');INSERT INTO gift_card_countries(name,iso_code,currency) VALUES('United States','US','USD'),('United Kingdom','GB','GBP'),('Canada','CA','CAD');
